scwin.f_AddRowPosition = function () {
  const row = gr_inoutInformation.getFocusedRowIndex();
  let rowObj = ds_inoutInformation.getRowJSON(row);
  let newRow = ds_inoutPosition.insertRow();
  ds_inoutPosition.setRowPosition(newRow);
  if (ds_inoutPosition.getRowCount() == 1) {
    ds_inoutPosition.setCellData(newRow, "ioNo", rowObj.ioNo);
    ds_inoutPosition.setCellData(newRow, "blck", rowObj.lblock);
    ds_inoutPosition.setCellData(newRow, "bay", rowObj.lbay);
    ds_inoutPosition.setCellData(newRow, "rw", rowObj.lrow);
    ds_inoutPosition.setCellData(newRow, "tier", rowObj.ltier);
    ds_inoutPosition.setCellData(newRow, "clntMgntNo", rowObj.clntMgntNo);
    ds_inoutPosition.setCellData(newRow, "inStdDt", ica_ioDt.getValue());
    ds_inoutPosition.setCellData(newRow, "rsltsQty", rowObj.qty);
    ds_inoutPosition.setCellData(newRow, "rsltsWt", rowObj.wt);
    ds_inoutPosition.setCellData(newRow, "rsltsCbm", rowObj.cbm);
  }
  let colid = gr_inoutPosition.getFocusedColumnID();
  if (rowObj.stockMgntYn == 1) {
    let row = gr_InIntendInformation.getFocusedRowIndex();
    let inIntendInfo = ds_InIntendInformation.getRowJSON(row);
    if (inIntendInfo.repClntNo != "000001")
      //20150605 jisoo, 보랄이 아닐경우 자동셋팅
      {
        ds_inoutPosition.setCellData(0, "clntMgntNo", $c.date.getServerDateTime($p, "yyyyMMdd")); //LOT번호
        ds_inoutPosition.setCellData(0, "blck", "Z"); //ZONE
      } else {
      colid = "blck";
      scwin.f_openCommonPopUp2(newRow, "blck", "");
    }
  } else {
    ds_inoutPosition.setCellData(newRow, "blck", "A");
  }
  ds_inoutPosition.setCellData(newRow, "commStsCd", "N1");
  ds_inoutPosition.setCellData(newRow, "bay", "01");
  ds_inoutPosition.setCellData(newRow, "rw", "01");
  ds_inoutPosition.setCellData(newRow, "tier", "1");
  gr_inoutPosition.setFocusedCell(newRow, colid ?? "commStsCd", false);
};

