scwin.f_Save = async function () {
  for (let i = 0; i < ds_inoutInformation.getRowCount(); i++) {
    ds_inoutInformation.setCellData(i, "vehclCd", scwin.hid_vehclNo);
    ds_inoutInformation.setCellData(i, "vehclNo", ed_vehclNm.getValue());
    ds_inoutInformation.setCellData(i, "copCoClntNo", ed_copCoClntNo.getValue());
    ds_inoutInformation.setCellData(i, "copCoClntNm", ed_copCoClntNm.getValue());
    ds_inoutInformation.setCellData(i, "eqKndCd", scwin.hid_eqKndCd); //규격코드
    ds_inoutInformation.setCellData(i, "ioDt", ica_ioDt.getValue());
    ds_inoutInformation.setCellData(i, "ioHh", ed_ioHh.getValue());
    ds_inoutInformation.setCellData(i, "vehclWt", ed_vehclWt.getValue());
    ds_inoutInformation.setCellData(i, "drvNm", ed_drvNm.getValue());
    ds_inoutInformation.setCellData(i, "drvTelNo", ed_drvTelNo.getValue());

    //check 수량,중량,CBM
    for (let j = 0; j < ds_inoutPosition.getRowCount(); j++) {
      if (ds_inoutInformation.getCellData(i, "ioNo") == ds_inoutPosition.getCellData(j, "ioNo")) {
        if (ds_inoutInformation.getCellData(i, "qty") != 0 && ds_inoutPosition.getCellData(j, "rsltsQty") == 0) {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_013, ["수량", "0"]);
          return;
        }
        if (ds_inoutInformation.getCellData(i, "wt") != 0 && ds_inoutPosition.getCellData(j, "rsltsWt") == 0) {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_013, ["중량", "0"]);
          return;
        }
        if (ds_inoutInformation.getCellData(i, "cbm") != 0 && ds_inoutPosition.getCellData(j, "rsltsCbm") == 0) {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_013, ["CBM", "0"]);
          return;
        }
      }
    }
  }
  for (let i = 0; i < ds_inoutPosition.getRowCount(); i++) {
    if (ds_inoutPosition.getCellData(i, "bay") == "" && ds_inoutPosition.getCellData(i, "rw") == "" && ds_inoutPosition.getCellData(i, "tier") == "") {
      ds_inoutPosition.setCellData(i, "bay", "01");
      ds_inoutPosition.setCellData(i, "rw", "01");
      ds_inoutPosition.setCellData(i, "tier", "1");
    }
  }
  let row = gr_InIntendInformation.getFocusedRowIndex();
  let inIntendInfo = ds_InIntendInformation.getRowJSON(row);
  if (inIntendInfo.transRsltsSeq != 0) {
    let positionQty = 0;
    let positionWt = 0;
    let positionCbm = 0;
    for (let i = 0; i < ds_inoutPosition.getRowCount(); i++) {
      if (parseFloat(ds_inoutPosition.getCellData(i, "rsltsQty")) < 0 || parseFloat(ds_inoutPosition.getCellData(i, "rsltsWt")) < 0 || parseFloat(ds_inoutPosition.getCellData(i, "rsltsCbm")) < 0) {
        await $c.win.alert($p, "수량,중량,CBM의 값에 -를 입력할 수 없습니다.");
        gr_inoutPosition.focus();
        return;
      }
      positionQty = positionQty + parseFloat(ds_inoutPosition.getCellData(i, "rsltsQty"));
      positionWt = positionWt + parseFloat(ds_inoutPosition.getCellData(i, "rsltsWt"));
      positionCbm = positionCbm + parseFloat(ds_inoutPosition.getCellData(i, "rsltsCbm"));
    } //for

    const row = gr_inoutInformation.getFocusedRowIndex();
    let rowObj = ds_inoutInformation.getRowJSON(row);
    if (rowObj.qty != positionQty || rowObj.wt != positionWt || rowObj.cbm != positionCbm) {
      await $c.win.alert($p, "LOCATION정보의 수량,중량,CBM의 합계는 품명정보의 수량,중량,CBM정보와 일치해야 합니다.");
      gr_inoutPosition.focus();
      return;
    } //if
  } //if

  if (ds_inoutPosition.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, Array("데이타"));
    return;
  }
  let ret = await $c.gus.cfValidate($p, [gr_inoutPosition], null, true);
  if (!ret) {
    return;
  }
  ret = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (!ret) {
    return;
  }
  if ($p.parent().rd_inQryCond.getValue() == "0") {
    $c.sbm.execute($p, sbm_save);
  } else {
    $c.sbm.execute($p, sbm_update);
  }
};

