scwin.f_OzReport = async function () {
  const row = gr_inoutInformation.getFocusedRowIndex();
  let inoutInfo = ds_inoutInformation.getRowJSON(row);
  if ((inoutInfo.ioNo == null || inoutInfo.ioNo == "") && (inoutInfo.coshippingNo == null || inoutInfo.coshippingNo == "")) {
    await $c.win.alert($p, "선택한 건에 대하여 발행정보가 존재하지 않습니다.");
    return;
  }
  let data = {
    odiName: "op_302_01_04p",
    reportName: "/ds/op/op_302_01_04p.ozr",
    odiParam: {
      ioNo: inoutInfo.ioNo,
      coshippingNo: inoutInfo.coshippingNo,
      ioClsCd: "I"
    },
    viewerParam: {
      viewer: 100,
      useprogressbar: false
    },
    formParam: {}
  };
  let opts = {
    type: 'viewer',
    printMode: 'view',
    exportFilename: "",
    exportMode: 'view'
  };
  if (cbx_printCheck.getValue() == "1" && cbx_previewCheck.getValue() == "1") {
    // 인쇄옵션, 미리보기 둘다 체크된 경우
    $c.ext.openOzReport($p, data, opts);
  } else if (cbx_printCheck.getValue() == "1") {
    // 인쇄옵션만 체크된 경우
    $c.ext.printOzReport($p, data, opts);
  } else if (cbx_previewCheck.getValue() == "1") {
    // 미리보기만 체크된 경우
    opts.printMode = 'silent';
    $c.ext.openOzReport($p, data, opts);
  } else {
    opts.type = "";
    opts.printMode = "";
    opts.exportFormat = "";
    opts.exportMode = "";
    $c.ext.printOzReport($p, data, opts);
  }
  $c.sbm.execute($p, sbm_printGDN);
};

