// GRID에서 선택된 오더 세부정보 확인 : 해당 오더유형별 페이지로 이동
//-------------------------------------------------------------------------
scwin.f_orderDetail = function () {
  let row = gr_InIntendInformation.getFocusedRowIndex();
  let inIntendInfo = ds_InIntendInformation.getRowJSON(row);
  if (row != -1 && row != null) {
    // 선택된 오더 정보 : 오더번호 / 오더유형
    paramObj = {
      odrNo: inIntendInfo.odrNo,
      type: "retrieve"
    };

    // 오더 종류가 벌크오더인 경우 - 화물구분(B : 벌크)       
    $c.win.openMenu($p, "벌크오더", "/ui/ds/sd/odrmgnt/odrreg/sd_402_01_02t.xml", "sd_402_01_02t.xml", paramObj);
  } else {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_056, new Array("오더현황"));
    return;
  }
};
scwin.f_changeTable = function (flag) {
  if (flag == 1) {
    gr_inoutInformation.setColumnVisible("coCd", true);
    gr_inoutInformation.setColumnVisible("tplSaleClsCd", true);
    gr_inoutInformation.setColumnVisible("bizLongCd", true);
    gr_inoutInformation.setColumnVisible("unitCd", true);
    gr_inoutInformation.setColumnVisible("tplPrdtKndCd", true);
    gr_inoutInformation.setColumnVisible("tplOrderClsCd", true);
    gr_inoutInformation.setColumnVisible("tplBuyRfslCd", true);
    gr_inoutInformation.setColumnVisible("tplStatecentCd", true);
    gr_inoutInformation.setColumnVisible("tplProcFctyCd", true);

    //Pallet정보 영역 숨기기
    grp_pallet.hide(); //ASIS : opt_palletGrid, opt_palletBtn
  } else if (flag == 2) {
    gr_inoutInformation.setColumnVisible("coCd", false);
    gr_inoutInformation.setColumnVisible("tplSaleClsCd", false);
    gr_inoutInformation.setColumnVisible("bizLongCd", false);
    gr_inoutInformation.setColumnVisible("unitCd", false);
    gr_inoutInformation.setColumnVisible("tplPrdtKndCd", false);
    gr_inoutInformation.setColumnVisible("tplOrderClsCd", false);
    gr_inoutInformation.setColumnVisible("tplBuyRfslCd", false);
    gr_inoutInformation.setColumnVisible("tplStatecentCd", false);
    gr_inoutInformation.setColumnVisible("tplProcFctyCd", false);

    //Pallet정보 영역 보이기
    grp_pallet.show(""); //ASIS : opt_palletGrid, opt_palletBtn
  }
};
scwin.f_openCommonPopUp2 = function (row, colid, data) {
  let con_wrkPlCd = null;
  let comm_cd = null;
  switch (colid) {
    case 'blck':
      con_wrkPlCd = ds_condition.getCellData(0, "wrkPlCd");
      comm_cd = ds_inoutInformation.getCellData(gr_inoutInformation.getFocusedRowIndex(), "commCd");

      // 작업장 팝업
      udc_comCode1.setSelectId("retrieveZoneInfo"); // XML상의 SELECT ID
      udc_comCode1.cfCommonPopUp(async ret => {
        if (ret != null) {
          if (ret[2] == "N/A") {
            return;
          }
          ds_inoutPosition.setCellData(row, "blck", ret[2]); //계정코드
        } else {
          ds_inoutPosition.setCellData(row, "blck", ""); //계정코드
          if (await $c.win.confirm($p, "Zone을추가하시겠습니까?")) {
            scwin.f_popupLacation();
          }
        }
      }, con_wrkPlCd, "", 'T', null, null, null, null, comm_cd, null, null, null, null);
      break;
  }
};
scwin.f_popupLacation = function () {
  let row = gr_InIntendInformation.getFocusedRowIndex();
  let inIntendInfo = ds_InIntendInformation.getRowJSON(row);
  let valueObject = {
    "wrkPlCd": inIntendInfo.inWrkPlCd
  };
  let win_url = "/ui/ds/op/wrkplan/stvwrkplan/op_204_04_01b.xml";
  let opts = {
    id: "op_204_04_01b",
    popupName: "로케이션관리",
    modal: true,
    type: "browserPopup",
    width: 1200,
    height: 750,
    title: "로케이션관리"
  };
  $c.win.openPopup($p, win_url, opts, valueObject);
};

