//-------------------------------------------------------------------------
// 품명 dataList 조회완료
//-------------------------------------------------------------------------
scwin.ds_inoutInformation_OnLoadCompleted = function (rowCnt) {
  if (ds_inoutInformation.getRowCount()) {
    ds_inoutInformation.setRowPosition(0);
  } else {
    ds_inoutPosition.removeAll();
    ds_inoutPosition.reform();
    ds_inoutPalet.removeAll();
    ds_inoutPalet.reform();
  }
  scwin.f_editSet();
  let row = gr_InIntendInformation.getFocusedRowIndex();
  let inIntendInfo = ds_InIntendInformation.getRowJSON(row);
  //거래처에 따라 품명정보를 다르게 보여줌
  if (inIntendInfo.repClntNo == "000010") {
    scwin.f_changeTable(1);
  } else {
    scwin.f_changeTable(2);
  }
};

//-------------------------------------------------------------------------
// 입고예정 물량정보 그리드 oncellclick
//-------------------------------------------------------------------------
scwin.gr_InIntendInformation_oncellclick = function (rowIndex, columnIndex, columnId) {
  let rowObj = ds_InIntendInformation.getRowJSON(rowIndex);
  ds_condition.setCellData(0, "transWrkIndictNo", rowObj.transWrkIndictNo);
  ds_condition.setCellData(0, "odrNo", rowObj.odrNo);
  ds_condition.setCellData(0, "commSeq", rowObj.commSeq);
  ds_condition.setCellData(0, "wrkPathSeq", rowObj.wrkPathSeq);
  ds_condition.setCellData(0, "wrkStpSeq", rowObj.wrkStpSeq);
  ds_condition.setCellData(0, "coshippingNo", rowObj.coshippingNo);
  ds_condition.setCellData(0, "transRsltsSeq", rowObj.transRsltsSeq);
  ds_condition.setCellData(0, "inNo", rowObj.inNo);
  ds_condition.setCellData(0, "commCd", rowObj.lcommCd);

  // scwin.f_detail();

  if ($p.parent().rd_inQryCond.getValue() == "0") {
    gr_inoutPosition.setReadOnly("grid", false);
    gr_inoutPalet.setReadOnly("grid", false);
    $c.gus.cfEnableObjects($p, [tbl_detail, tbl_detail2]);
  } else {
    gr_inoutPosition.setReadOnly("grid", true);
    gr_inoutPalet.setReadOnly("grid", true);
    $c.gus.cfDisableObjects($p, [tbl_detail, tbl_detail2]);
    $c.gus.cfEnableObjects($p, [btn_save, btn_delete]);
  }

  //iFrame0의 행추가,삭제,취소 버튼 disable
  scwin.f_BtnSetting(3);
  scwin.f_BtnSetting(6);
  if (rowObj.transRsltsSeq != 0) {
    if ($p.parent().rd_inQryCond.getValue() == "0") {
      $c.gus.cfDisableObjects($p, [ed_vehclNo, ed_vehclNm, ed_copCoClntNo, ed_copCoClntNm]);
    } else {
      $c.gus.cfDisableObjects($p, [ed_vehclNo, ed_vehclNm, ed_copCoClntNo, ed_copCoClntNm, ed_ioDt, ed_ioHh]);
    }
  }

  // 더블클릭으로 개선요청
  /* if (columnId == "odrNo") {
      // 오더세부사항 조회 
      scwin.f_orderDetail();
  } */
  clearTimeout(scwin.clickTimer);
  scwin.clickTimer = setTimeout(function () {
    scwin.f_detail();
  }, 300);
};

