//-------------------------------------------------------------------------
// LOCATION 정보 dataList oncelldatachange
//-------------------------------------------------------------------------
scwin.ds_inoutPosition_oncelldatachange = function (info) {
  const row = gr_inoutInformation.getFocusedRowIndex();
  let inoutInfo = ds_inoutInformation.getRowJSON(row);
  let qty = $c.num.parseFloat($p, inoutInfo.qty);
  let wt = $c.num.parseFloat($p, inoutInfo.wt);
  let cbm = $c.num.parseFloat($p, inoutInfo.cbm);
  let p_qty = $c.num.parseFloat($p, ds_inoutPosition.getCellData(info.rowIndex, "rsltsQty"));
  if (info.colID == "rsltsQty") {
    if (ds_inoutPosition.getCellData(info.rowIndex, 'rsltsWt') == 0) {
      ds_inoutPosition.setCellData(info.rowIndex, 'rsltsWt', (p_qty * wt / qty).toString()); //데이터 타입 확인 필요
    }
    if (ds_inoutPosition.getCellData(info.rowIndex, 'rsltsCbm') == 0) {
      ds_inoutPosition.setCellData(info.rowIndex, 'rsltsCbm', (p_qty * cbm / qty).toString()); //데이터 타입 확인 필요
    }
  }
};

